const house_id = env.get("house_id");
const filterMode = env.get("entity_filter_mode"); // entity|domain|both
const allowedDomains = env.get("allowed_entity_domains");
const allowedEntities = env.get("allowed_entity_ids");

// Extract the full entity_id
const entityId = msg.payload.entity_id;

// Extract the domain from the entity_id (everything before the dot)
const domain = entityId.split('.')[0];

// Apply filtering based on mode
if (filterMode === "domain") {
    // Allow any entity from allowed domains
    if (!allowedDomains.includes(domain)) {
        return null; // Drop message
    }
} else if (filterMode === "entity") {
    // Allow only explicitly listed entities
    if (!allowedEntities.includes(entityId)) {
        return null; // Drop message
    }
} else if (filterMode === "both") {
    if (!allowedEntities.includes(entityId) && !allowedDomains.includes(domain)) {
        return null; // Drop message
    }
}

// Initialize attributes based on domain
let attributes = null;
switch (domain) {
    case "cover":
        attributes = {
            "current_position": msg.payload.event.new_state.attributes.current_position
        };
        break;
    case "climate":
        var targetTemperature = msg.payload.event.new_state.attributes.temperature;
        if (targetTemperature == undefined || targetTemperature == null || targetTemperature == "") {
            targetTemperature = msg.payload.event.old_state.attributes.temperature;

            if (targetTemperature == undefined || targetTemperature == null || targetTemperature == "") {
                targetTemperature = msg.payload.event.new_state.attributes.prev_target_temp;
            }
        }
        attributes = {
            "target_temperature": targetTemperature,
            "current_temperature": msg.payload.event.new_state.attributes.current_temperature,
            "hvac_action": msg.payload.event.new_state.attributes.hvac_action,
            "fan_mode": msg.payload.event.new_state.attributes.fan_mode
        };
        break;
    case "alarm_control_panel":
        attributes = {
            "open_sensors": msg.payload.event.new_state.attributes.open_sensors,
            "delay": msg.payload.event.new_state.attributes.delay
        };
        break;
}

// Build MQTT topic
msg.topic = "house/" + house_id + "/state/" + domain + "/" + entityId.split('.')[1];
msg.payload = {
    state: msg.payload.event.new_state.state,
    last_changed: msg.payload.event.new_state.last_changed,
    timestamp: Math.floor(Date.now() / 1000) // Unix time in seconds
};
msg.retain = true;

// Add attributes if applicable
if (attributes && Object.keys(attributes).length > 0) {
    msg.payload.attributes = attributes;
}

// Pass the message along
return msg;

// Extract timestamp from msg.payload
let timestamp = msg.payload;

// Convert to Date object
let dateObj = new Date(timestamp);

// Define days of the week and months in Spanish
const days = ["Domingo", "Lunes", "Martes", "Miércoles", "Jueves", "Viernes", "Sábado"];
const months = [
    "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio",
    "Julio", "Agosto", "Setiembre", "Octubre", "Noviembre", "Diciembre"
];

// Extract day of the week and month name
let dayOfWeek = days[dateObj.getDay()];
let dayOfMonth = dateObj.getDate();
let monthName = months[dateObj.getMonth()];

// Format date as "Lunes, 14 de Marzo"
let dateStr = `${dayOfWeek}, ${dayOfMonth} de ${monthName}`;

// Extract hours and minutes (keep hours as a number for comparisons)
let hours = dateObj.getHours(); // Keep as number
let minutes = dateObj.getMinutes();

// Format time as HH:mm (adding leading zeros)
let timeStr = `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}`;

// Determine greeting based on hour
let greeting;
if (hours >= 6 && hours < 12) {
    greeting = "Buenos Días"; // 6:00 - 11:59
} else if (hours >= 12 && hours < 20) {
    greeting = "Buenas Tardes"; // 12:00 - 19:59
} else {
    greeting = "Buenas Noches"; // 20:00 - 5:59
}

// Create new messages for each entity
let msgDate = {
    payload: {
        entity_id: "sensor.date_text",
        event: {
            new_state: {
                state: dateStr
            }
        }
    }
};

let msgTime = {
    payload: {
        entity_id: "sensor.time_text",
        event: {
            new_state: {
                state: timeStr
            }
        }
    }
};

let msgGreeting = {
    payload: {
        entity_id: "sensor.greeting_text",
        event: {
            new_state: {
                state: greeting
            }
        }
    }
};

// Return messages to three outputs
return [msgDate, msgTime, msgGreeting];

const house_id = env.get("house_id");

msg.topic = "house/" + house_id + "/app/state/heartbeat";
msg.payload = {
    state: "pong",
    timestamp: msg.timestamp = new Date().toISOString()
};
msg.retain = false;
msg.qos = 1;

// Pass the message along
return msg;

const house_id = env.get("house_id");

msg.topic = "house/" + house_id + "/app/command/houseStructure";
msg.payload = {
    command: "reload",
    timestamp: msg.timestamp = new Date().toISOString()
};
msg.retain = false;
msg.qos = 2;

// Pass the message along
return msg;

const house_id = env.get("house_id");

msg.action = "subscribe";
msg.topic = "house/" + house_id + "/app/command/heartbeat";
msg.qos = 1;
return msg;

// Extract the topic components
const topicParts = msg.topic.split('/');
if (topicParts.length < 5 || topicParts[2] !== 'command') {
    node.error("Invalid topic format. Expected format: house/<house_id>/command/<domain>/<entity_id>", msg);
    return null;
}

// Validate payload
if (!msg.payload || !msg.payload.command) {
    node.error("Invalid payload format. Must include 'command' field.", msg);
    return null;
}

const userName = msg.payload.metadata.user_name;
const userEMail = msg.payload.metadata.user_email;
const domain = topicParts[3]; // The <domain> part of the topic
const entityId = topicParts[4]; // The <entity_id> part of the topic
var command = msg.payload.command; // e.g., "light.turn_on", "light.toggle"
var parameters = msg.payload.parameters || {}; // Optional parameters (e.g., brightness, color, etc.)

var loggerMsg = {};

if (domain == 'alarm_control_panel') {
    switch (msg.payload.parameters.alarm_mode) {
        case "armed_away":
            command = "alarm_arm_away";
            break;
        case "armed_custom_bypass":
            command = "alarm_arm_custom_bypass";
            break;
        case "armed_home":
            command = "alarm_arm_home";
            break;
        case "armed_night":
            command = "alarm_arm_night";
            break;
        case "armed_vacation":
            command = "alarm_arm_vacation";
            break;
        case "disarmed":
            command = "alarm_disarm";
            break;
        case "triggered":
            command = "alarm_trigger";
            break;
    }

    command = "alarm_control_panel." + command;
    parameters = null;
}

// Build the output message
msg.payload = {
    action: command,
    target: {
        entity_id: [domain + "." + entityId]
    }
};

if (parameters && Object.keys(parameters).length > 0) {
    msg.payload.data = parameters;
}

loggerMsg.payload = {
    action: "logbook.log",
    data: {
        name: entityId,
        entity_id: domain + "." + entityId,
        message: "turzi App - " + userName + " (" + command.split('.')[1] + ")"
    }
};

// Pass the constructed message
return [loggerMsg, msg];

const house_id = env.get("house_id");

msg.action = "subscribe";
msg.topic = "house/" + house_id + "/command/#";
msg.qos = 0;
return msg;
